const ring = global.get('alerts') || [];
// Newest first, bounded to 500 (writers should already cap, but we double-clip).
const out = [...ring].slice(-500).reverse();
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.statusCode = 200;
msg.payload = { alerts: out, count: out.length };
return msg;

// Append the captured error onto global.alerts (bounded ring of 500).
const ring = global.get('alerts') || [];
const err = msg.error || {};
const entry = {
  id: 'err-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8),
  source: (err.source && err.source.id) || 'unknown',
  category: 'runtime',
  severity: 'warning',
  timestamp: new Date().toISOString(),
  status: 'open',
  message: String((err && err.message) || msg.payload || 'unknown error').slice(0, 500)
};
ring.push(entry);
while (ring.length > 500) ring.shift();
global.set('alerts', ring);
return null;  // do not propagate
